/**
 * Post-build patch for dist/server/wrangler.json generated by @astrojs/cloudflare.
 *
 * Cloudflare Pages rejects several things the adapter auto-generates for the
 * server worker config. This script strips them all out so the Pages deployment succeeds.
 *
 * Removed fields:
 *   - SESSION     kv_namespace  (no id field — we don't use Astro sessions)
 *   - ASSETS      service binding (reserved name in Cloudflare Pages)
 *   - main        (Pages uses _worker.js convention, not "main")
 *   - rules       (not supported in Pages wrangler configs)
 *   - images      (not supported in Pages wrangler configs)
 *   - pages_build_output_dir is kept only if "main" is absent (can't have both)
 */

import { readFileSync, writeFileSync, existsSync } from 'fs';
import { join } from 'path';

const wranglerPath = join('dist', 'server', 'wrangler.json');

if (!existsSync(wranglerPath)) {
  console.log(`ℹ  ${wranglerPath} not found — skipping patch.`);
  process.exit(0);
}

const config = JSON.parse(readFileSync(wranglerPath, 'utf8'));

// Fields not allowed in Cloudflare Pages wrangler configs
const REMOVE_TOP_LEVEL = ['main', 'rules', 'images'];
for (const field of REMOVE_TOP_LEVEL) {
  if (field in config) {
    delete config[field];
    console.log(`✓ Removed "${field}" from wrangler.json`);
  }
}

// Remove SESSION KV namespace (missing required "id" field — we don't use sessions)
if (Array.isArray(config.kv_namespaces)) {
  const before = config.kv_namespaces.length;
  config.kv_namespaces = config.kv_namespaces.filter((kv) => kv.binding !== 'SESSION');
  if (config.kv_namespaces.length === 0) delete config.kv_namespaces;
  if ((config.kv_namespaces?.length ?? 0) < before) {
    console.log('✓ Removed SESSION KV namespace from wrangler.json');
  }
}

// Remove ASSETS service binding (reserved name in Cloudflare Pages)
if (Array.isArray(config.services)) {
  const before = config.services.length;
  config.services = config.services.filter((s) => s.binding !== 'ASSETS');
  if (config.services.length === 0) delete config.services;
  if ((config.services?.length ?? 0) < before) {
    console.log('✓ Removed ASSETS service binding from wrangler.json');
  }
}

// Also handle ASSETS as a top-level assets field
if (config.assets?.binding === 'ASSETS') {
  delete config.assets;
  console.log('✓ Removed top-level assets.binding from wrangler.json');
}

writeFileSync(wranglerPath, JSON.stringify(config, null, 2));
console.log(`✓ Patched ${wranglerPath}`);
